ee:variables.ee:set-variable:
%dw 2.0
output application/json
---
{
    template: "You are a helpful assistant.",
    instructions: "Answer the request politely. Call a tool when it helps.",
    dataset: payload.question,
    tools: [
        {
            // 'type' must be quoted: it is a reserved word in DataWeave
            'type': "function",
            function: {
                name: "get_weather",
                description: "Get the current weather for a city",
                parameters: {
                    'type': "object",
                    properties: { city: { 'type': "string", description: "The city name" } },
                    required: ["city"]
                }
            }
        },
        {
            'type': "function",
            function: {
                name: "search_docs",
                description: "Search internal company documents",
                parameters: {
                    'type': "object",
                    properties: { query: { 'type': "string", description: "What to search for" } },
                    required: ["query"]
                }
            }
        }
    ]
}

%dw 2.0
output application/json
// The tool-call decisions the LLM returned in step 2:
var calls = payload.tools default []
---
calls map (call) -> {
    tool: call.function.name,
    // 'arguments' is a JSON *string*, so read() parses it into an object
    args: read(call.function.arguments default "{}", "application/json"),
    result:
        if (call.function.name == "get_weather")
            "It is 33 C and sunny."
        else if (call.function.name == "search_docs")
            "Invoices are due within 30 days per policy X-123."
        else
            "No matching tool."
}
